{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>EX Intelligence — 임원 1:1 피칭 컴패니언</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;1,400&family=IBM+Plex+Mono:wght@300;400;500&family=Noto+Sans+KR:wght@300;400;500&display=swap');

:root {
  --bg: #f5f2ec;
  --surface: #ffffff;
  --surface2: #f0ece3;
  --border: #ddd8cc;
  --border2: #c8c2b4;
  --ink: #1a1814;
  --ink2: #4a4640;
  --ink3: #8a867e;
  --ink4: #b8b4ac;
  --gold: #8a6f3a;
  --gold2: #c4a060;
  --blue: #3a5a7a;
  --green: #3a6a4a;
  --red: #7a3a3a;
  --serif: 'Playfair Display', serif;
  --mono: 'IBM Plex Mono', monospace;
  --sans: 'Noto Sans KR', sans-serif;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
  background: var(--bg);
  color: var(--ink);
  font-family: var(--sans);
  min-height: 100vh;
}

/* ── LAYOUT ── */
.app {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: auto 1fr;
  min-height: 100vh;
}

/* ── TOPBAR ── */
.topbar {
  grid-column: 1 / -1;
  background: var(--ink);
  color: var(--bg);
  display: flex;
  align-items: center;
  padding: 0 28px;
  height: 52px;
  gap: 20px;
}

.topbar-brand {
  font-family: var(--serif);
  font-size: 0.95rem;
  color: var(--gold2);
  flex: 1;
  letter-spacing: 0.02em;
}

.topbar-brand span {
  font-family: var(--mono);
  font-size: 0.6rem;
  color: var(--ink3);
  margin-left: 10px;
  letter-spacing: 0.1em;
}

.context-chips {
  display: flex;
  gap: 8px;
}

.ctx-chip {
  font-family: var(--mono);
  font-size: 0.58rem;
  padding: 3px 10px;
  border: 1px solid #3a3830;
  color: var(--ink3);
  letter-spacing: 0.06em;
}

.ctx-chip.active {
  border-color: var(--gold);
  color: var(--gold2);
}

/* Timer */
.timer-wrap { display: flex; align-items: center; gap: 8px; }

.timer-display {
  font-family: var(--mono);
  font-size: 1.25rem;
  color: var(--bg);
  letter-spacing: 0.1em;
  min-width: 60px;
}

.timer-display.warn { color: var(--gold2); }
.timer-display.over { color: #e07070; animation: blink 1s infinite; }

@keyframes blink { 50% { opacity: 0.4; } }

.btn-t {
  background: transparent;
  border: 1px solid #3a3830;
  color: var(--ink3);
  font-family: var(--mono);
  font-size: 0.6rem;
  padding: 4px 10px;
  cursor: pointer;
  letter-spacing: 0.06em;
  transition: all 0.15s;
}
.btn-t:hover { border-color: var(--gold); color: var(--gold2); }
.btn-t.running { border-color: var(--gold2); color: var(--gold2); }

/* ── LEFT NAV ── */
.slide-nav {
  background: var(--surface);
  border-right: 1px solid var(--border);
  padding: 0;
  overflow-y: auto;
}

.nav-mode-strip {
  background: var(--ink);
  padding: 14px 20px;
  font-family: var(--mono);
  font-size: 0.58rem;
  color: var(--ink3);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.nav-mode-strip strong {
  color: var(--gold2);
  display: block;
  font-size: 0.65rem;
  margin-bottom: 2px;
}

.card-deck-label {
  padding: 14px 20px 6px;
  font-family: var(--mono);
  font-size: 0.55rem;
  color: var(--ink4);
  letter-spacing: 0.1em;
  text-transform: uppercase;
  border-bottom: 1px solid var(--border);
}

.slide-item {
  padding: 14px 20px;
  cursor: pointer;
  border-left: 3px solid transparent;
  border-bottom: 1px solid var(--border);
  transition: all 0.15s;
}

.slide-item:hover { background: var(--surface2); }

.slide-item.active {
  border-left-color: var(--gold);
  background: var(--surface2);
}

.slide-item.reserve {
  opacity: 0.5;
}

.slide-item.reserve.active { opacity: 1; }

.s-num {
  font-family: var(--mono);
  font-size: 0.58rem;
  color: var(--ink4);
  margin-bottom: 4px;
}

.slide-item.active .s-num { color: var(--gold); }

.s-title {
  font-size: 0.8rem;
  color: var(--ink2);
  line-height: 1.4;
  font-weight: 500;
}

.slide-item.active .s-title { color: var(--ink); }

.s-badge {
  display: inline-block;
  font-family: var(--mono);
  font-size: 0.5rem;
  padding: 1px 5px;
  margin-top: 4px;
  letter-spacing: 0.06em;
}

.badge-core { background: rgba(138,111,58,0.1); color: var(--gold); }
.badge-reserve { background: rgba(58,90,122,0.1); color: var(--blue); }
.badge-close { background: rgba(58,106,74,0.1); color: var(--green); }

.nav-key-hint {
  padding: 12px 20px;
  font-family: var(--mono);
  font-size: 0.55rem;
  color: var(--ink4);
  letter-spacing: 0.05em;
  line-height: 1.8;
}

kbd {
  background: var(--surface2);
  border: 1px solid var(--border2);
  padding: 1px 4px;
  font-size: 0.55rem;
  font-family: var(--mono);
}

/* ── MAIN ── */
.main-content {
  overflow-y: auto;
  padding: 36px 44px;
  max-width: 780px;
}

/* Progress strip */
.progress-strip {
  display: flex;
  gap: 4px;
  margin-bottom: 32px;
}

.prog-seg {
  height: 3px;
  flex: 1;
  background: var(--border);
  transition: background 0.3s;
}

.prog-seg.done { background: var(--gold2); }
.prog-seg.current { background: var(--gold); }

/* Slide header */
.slide-hd {
  margin-bottom: 28px;
}

.slide-hd-eyebrow {
  font-family: var(--mono);
  font-size: 0.6rem;
  color: var(--ink4);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  margin-bottom: 10px;
  display: flex;
  align-items: center;
  gap: 10px;
}

.eyebrow-time {
  background: var(--ink);
  color: var(--gold2);
  font-family: var(--mono);
  font-size: 0.55rem;
  padding: 2px 8px;
  letter-spacing: 0.08em;
}

.slide-hd-title {
  font-family: var(--serif);
  font-size: 2rem;
  color: var(--ink);
  line-height: 1.15;
  margin-bottom: 8px;
}

.slide-hd-title em {
  color: var(--gold);
  font-style: italic;
}

.slide-hd-sub {
  font-size: 0.85rem;
  color: var(--ink3);
  line-height: 1.6;
  max-width: 520px;
}

/* ── BLOCKS ── */

/* Anchor */
.anchor-block {
  border-top: 2px solid var(--gold);
  border-bottom: 1px solid var(--border);
  padding: 20px 0;
  margin-bottom: 24px;
}

.block-eyebrow {
  font-family: var(--mono);
  font-size: 0.55rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  margin-bottom: 10px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.block-eyebrow::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--border);
}

.eyebrow-gold { color: var(--gold); }
.eyebrow-blue { color: var(--blue); }
.eyebrow-green { color: var(--green); }
.eyebrow-red { color: var(--red); }

.anchor-sentence {
  font-family: var(--serif);
  font-size: 1.35rem;
  line-height: 1.6;
  color: var(--ink);
}

.anchor-sentence strong { color: var(--gold); font-weight: 600; }

/* Exec note */
.exec-note {
  background: var(--surface2);
  border: 1px solid var(--border);
  padding: 16px 20px;
  margin-bottom: 20px;
  display: flex;
  gap: 16px;
}

.exec-note-icon {
  font-family: var(--serif);
  font-size: 1.2rem;
  color: var(--gold2);
  min-width: 20px;
  padding-top: 2px;
}

.exec-note-body {
  font-size: 0.82rem;
  color: var(--ink2);
  line-height: 1.7;
}

.exec-note-body strong {
  color: var(--ink);
  font-weight: 500;
}

/* Question block */
.q-block {
  border: 1px solid var(--border);
  padding: 20px 24px;
  margin-bottom: 20px;
  position: relative;
}

.q-block::before {
  content: '';
  position: absolute;
  top: 0; left: 0; bottom: 0;
  width: 3px;
  background: var(--blue);
}

.q-sentence {
  font-family: var(--serif);
  font-size: 1.1rem;
  font-style: italic;
  color: var(--blue);
  line-height: 1.6;
  margin-bottom: 10px;
}

.q-reading {
  font-size: 0.78rem;
  color: var(--ink3);
  line-height: 1.7;
}

.q-reading strong { color: var(--ink2); font-weight: 500; }

/* Silence block */
.silence-block {
  border: 1px solid var(--border);
  padding: 18px 24px;
  margin-bottom: 20px;
  background: var(--surface);
  position: relative;
}

.silence-block::before {
  content: '';
  position: absolute;
  top: 0; left: 0; bottom: 0;
  width: 3px;
  background: var(--green);
}

.silence-title {
  font-family: var(--mono);
  font-size: 0.62rem;
  color: var(--green);
  letter-spacing: 0.1em;
  margin-bottom: 8px;
}

.silence-body {
  font-size: 0.82rem;
  color: var(--ink2);
  line-height: 1.7;
}

/* Reserve cards */
.reserve-section {
  margin-top: 28px;
  padding-top: 20px;
  border-top: 1px dashed var(--border2);
}

.reserve-label {
  font-family: var(--mono);
  font-size: 0.58rem;
  color: var(--ink4);
  letter-spacing: 0.1em;
  text-transform: uppercase;
  margin-bottom: 12px;
}

.reserve-cards {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.reserve-card {
  background: var(--surface);
  border: 1px solid var(--border);
  padding: 12px 16px;
  cursor: pointer;
  transition: all 0.15s;
  display: flex;
  align-items: flex-start;
  gap: 12px;
}

.reserve-card:hover { border-color: var(--gold2); }

.rc-indicator {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--blue);
  margin-top: 6px;
  min-width: 6px;
}

.rc-title {
  font-size: 0.8rem;
  color: var(--ink2);
  font-weight: 500;
  margin-bottom: 3px;
}

.rc-trigger {
  font-size: 0.72rem;
  color: var(--ink4);
  font-family: var(--mono);
  letter-spacing: 0.04em;
}

/* Escape */
.escape-section {
  margin-top: 24px;
}

.escape-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.escape-card {
  flex: 1;
  min-width: 180px;
  border: 1px solid var(--border);
  padding: 14px 16px;
  background: var(--surface);
}

.ec-num {
  font-family: var(--mono);
  font-size: 0.55rem;
  color: var(--red);
  letter-spacing: 0.1em;
  margin-bottom: 6px;
}

.ec-label {
  font-size: 0.75rem;
  color: var(--ink);
  font-weight: 500;
  margin-bottom: 6px;
}

.ec-script {
  font-family: var(--serif);
  font-style: italic;
  font-size: 0.85rem;
  color: var(--blue);
  line-height: 1.5;
}

/* Objective banner */
.obj-banner {
  background: var(--ink);
  padding: 16px 20px;
  margin-bottom: 28px;
  display: flex;
  gap: 20px;
  align-items: center;
}

.obj-item {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.obj-label {
  font-family: var(--mono);
  font-size: 0.52rem;
  color: var(--ink3);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.obj-value {
  font-family: var(--mono);
  font-size: 0.72rem;
  color: var(--gold2);
  letter-spacing: 0.04em;
}

.obj-divider {
  width: 1px;
  height: 30px;
  background: #3a3830;
}

/* Scrollbar */
::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border2); }

/* Anim */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(6px); }
  to { opacity: 1; transform: none; }
}

.slide-content { animation: fadeIn 0.25s ease; }
</style>
</head>
