<div class="app">

  <!-- TOPBAR -->
  <header class="topbar">
    <div class="topbar-brand">
      EX Intelligence <span>임원 1:1 피칭 컴패니언</span>
    </div>
    <div class="context-chips">
      <div class="ctx-chip active">상위 임원 2단계↑</div>
