let current = 0;
let timerSec = 0;
let timerOn = false;
let timerInt = null;

function renderNav() {
  const nav = document.getElementById('slideNav');
  const coreSlides = slides.filter(s => s.type === 'core');
  const reserveSlides = slides.filter(s => s.type === 'reserve');

  let html = '<div class="card-deck-label">핵심 3장</div>';
  coreSlides.forEach((s, i) => {
    const idx = slides.indexOf(s);
    const badgeMap = { core: 'badge-core', reserve: 'badge-reserve', close: 'badge-close' };
    const badgeLabel = { core: '핵심', reserve: '예비', close: '클로징' };
    html += `
      <div class="slide-item ${idx === current ? 'active' : ''}" onclick="goTo(${idx})">
        <div class="s-num">${s.num}</div>
        <div class="s-title">${s.title}</div>
        <span class="s-badge ${badgeMap[s.badge]}">${badgeLabel[s.badge]}</span>
      </div>
    `;
  });

  html += '<div class="card-deck-label" style="margin-top:8px">예비 카드 — 필요시만</div>';
  reserveSlides.forEach(s => {
    const idx = slides.indexOf(s);
    html += `
      <div class="slide-item reserve ${idx === current ? 'active' : ''}" onclick="goTo(${idx})">
        <div class="s-num">${s.num}</div>
        <div class="s-title">${s.title}</div>
        <div style="font-family:var(--mono);font-size:0.55rem;color:var(--ink4);margin-top:3px">${s.trigger ? s.trigger.slice(0,22)+'…' : ''}</div>
        <span class="s-badge badge-reserve">예비</span>
      </div>
    `;
  });

  nav.innerHTML = html;
}

function renderMain() {
  const s = slides[current];
  const content = document.getElementById('mainContent');
  const coreCount = slides.filter(x => x.type === 'core').length;
  const coreIndex = slides.filter(x => x.type === 'core').indexOf(s);

  let html = `<div class="slide-content">`;

  // Progress (core only)
  if (s.type === 'core') {
    html += `<div class="progress-strip">`;
    for (let i = 0; i < coreCount; i++) {
      const cls = i < coreIndex ? 'done' : i === coreIndex ? 'current' : '';
      html += `<div class="prog-seg ${cls}"></div>`;
    }
    html += `</div>`;
  }

  // Objective banner
  html += `
    <div class="obj-banner">
      <div class="obj-item"><div class="obj-label">관계</div><div class="obj-value">상위 임원 2단계↑</div></div>
      <div class="obj-divider"></div>
      <div class="obj-item"><div class="obj-label">사전 인지</div><div class="obj-value">이전 보고 있음</div></div>
      <div class="obj-divider"></div>
      <div class="obj-item"><div class="obj-label">목적</div><div class="obj-value">방향성 동의</div></div>
      <div class="obj-divider"></div>
      <div class="obj-item"><div class="obj-label">모드</div><div class="obj-value">${s.type === 'reserve' ? '예비 카드' : `${s.num} / 03`}</div></div>
    </div>
  `;

  // Header
  html += `
    <div class="slide-hd">
      <div class="slide-hd-eyebrow">
        ${s.type === 'reserve' ? '예비 카드' : `SLIDE ${s.num}`}
