        ${s.trigger ? `<span style="font-size:0.55rem;color:var(--blue)">트리거: ${s.trigger}</span>` : ''}
      </div>
      <div class="slide-hd-title">${s.title}</div>
      <div class="slide-hd-sub">${s.sub}</div>
    </div>
  `;

  // Anchor
  html += `
    <div class="anchor-block">
      <div class="block-eyebrow eyebrow-gold">앵커 — 이것 하나만</div>
      <div class="anchor-sentence">${s.anchor}</div>
    </div>
