  // Exec note
  if (s.execNote) {
    html += `
      <div class="exec-note">
        <div class="exec-note-icon">${s.execNote.icon}</div>
        <div class="exec-note-body">${s.execNote.text}</div>
      </div>
    `;
  }

  // Question
  if (s.question) {
    html += `
      <div class="q-block">
        <div class="block-eyebrow eyebrow-blue">판단 끌어내기 질문</div>
        <div class="q-sentence">${s.question.sentence}</div>
        <div class="q-reading">${s.question.reading}</div>
      </div>
    `;
  }

  // Silence
  if (s.silence) {
    html += `
      <div class="silence-block">
        <div class="silence-title">▸ 침묵 프로토콜</div>
        <div class="silence-body">${s.silence}</div>
      </div>
    `;
  }

  // Concern list (R3)
  if (s.concerns) {
    html += `<div style="margin-bottom:20px">`;
    s.concerns.forEach(c => {
      html += `
        <div style="border:1px solid var(--border);padding:14px 18px;margin-bottom:8px;background:var(--surface)">
          <div style="font-family:var(--serif);font-style:italic;font-size:0.95rem;color:var(--blue);margin-bottom:6px">${c.q}</div>
          <div style="font-size:0.82rem;color:var(--ink2);line-height:1.6">${c.a}</div>
        </div>
      `;
    });
    html += `</div>`;
  }

  // Escapes
  if (s.escapes) {
    html += `
      <div class="escape-section">
        <div class="block-eyebrow eyebrow-red" style="margin-bottom:10px">막혔을 때</div>
        <div class="escape-row">
          ${s.escapes.map((e, i) => `
            <div class="escape-card">
              <div class="ec-num">0${i+1}</div>
              <div class="ec-label">${e.label}</div>
              <div class="ec-script">${e.script}</div>
            </div>
          `).join('')}
        </div>
      </div>
    `;
  }

  html += `</div>`;
  content.innerHTML = html;
  content.scrollTop = 0;
}

function goTo(i) {
  current = i;
  renderNav();
  renderMain();
}

function toggleTimer() {
  if (timerOn) {
    clearInterval(timerInt);
    timerOn = false;
    document.getElementById('btnRun').textContent = '▶ 재개';
    document.getElementById('btnRun').classList.remove('running');
  } else {
    timerOn = true;
    document.getElementById('btnRun').textContent = '⏸ 정지';
    document.getElementById('btnRun').classList.add('running');
    timerInt = setInterval(() => {
      timerSec++;
      const m = String(Math.floor(timerSec / 60)).padStart(2, '0');
      const s = String(timerSec % 60).padStart(2, '0');
      const d = document.getElementById('timerDisplay');
      d.textContent = `${m}:${s}`;
      d.className = timerSec >= 600 ? 'timer-display over' : timerSec >= 480 ? 'timer-display warn' : 'timer-display';
    }, 1000);
  }
}

function resetTimer() {
  clearInterval(timerInt);
  timerOn = false;
  timerSec = 0;
  document.getElementById('timerDisplay').textContent = '00:00';
  document.getElementById('timerDisplay').className = 'timer-display';
  document.getElementById('btnRun').textContent = '▶ 시작';
  document.getElementById('btnRun').classList.remove('running');
}

document.addEventListener('keydown', e => {
  const coreSlides = slides.filter(s => s.type === 'core');
  const coreIdx = coreSlides.indexOf(slides[current]);
  if (e.key === 'ArrowRight' && coreIdx < coreSlides.length - 1) {
    goTo(slides.indexOf(coreSlides[coreIdx + 1]));
  }
  if (e.key === 'ArrowLeft' && coreIdx > 0) {
    goTo(slides.indexOf(coreSlides[coreIdx - 1]));
  }
  if (e.key === ' ') { e.preventDefault(); toggleTimer(); }
});

renderNav();
renderMain();
</script>
